import React, { useState, useEffect, useMemo } from "react";

const toCents = (val) => Math.round(val * 100);
const fromCents = (val) => (val / 100).toFixed(2);

export default function SplitPaymentUX() {
    const [total, setTotal] = useState(1000);
    const [participants, setParticipants] = useState([
        { id: 1, name: "A", amount: 500 },
        { id: 2, name: "B", amount: 500 }
    ]);

    const [isEqualSplit, setIsEqualSplit] = useState(true);
    const [autoAdjust, setAutoAdjust] = useState(true);

    // Equal split
    useEffect(() => {
        if (isEqualSplit && participants.length > 0) {
            const totalCents = toCents(total);
            const base = Math.floor(totalCents / participants.length);
            let remainder = totalCents % participants.length;

            const updated = participants.map((p) => {
                let amt = base;
                if (remainder > 0) {
                    amt += 1;
                    remainder--;
                }
                return { ...p, amount: parseFloat(fromCents(amt)) };
            });

            setParticipants(updated);
        }
    }, [total, participants.length, isEqualSplit]);

    const totalAllocated = useMemo(() => {
        return participants.reduce((sum, p) => sum + p.amount, 0);
    }, [participants]);

    const remaining = +(total - totalAllocated).toFixed(2);
    const isValid = remaining === 0;

    const progress = Math.min((totalAllocated / total) * 100, 100);

    // Handle amount change
    const handleAmountChange = (id, value) => {
        setIsEqualSplit(false);

        let updated = participants.map((p) =>
            p.id === id ? { ...p, amount: parseFloat(value) || 0 } : p
        );

        // Auto adjust last person
        if (autoAdjust && updated.length > 1) {
            const totalCents = toCents(total);

            const sumExceptLast = updated
                .slice(0, -1)
                .reduce((sum, p) => sum + toCents(p.amount), 0);

            const lastAmount = totalCents - sumExceptLast;

            updated[updated.length - 1].amount = parseFloat(
                fromCents(lastAmount)
            );
        }

        setParticipants(updated);
    };

    const addParticipant = () => {
        setParticipants((prev) => [
            ...prev,
            {
                id: Date.now(),
                name: "",
                amount: 0
            }
        ]);
    };

    const removeParticipant = (id) => {
        setParticipants((prev) => prev.filter((p) => p.id !== id));
    };

    return (
        <div style={styles.container}>
            <h2>💸 Split Payment</h2>

            {/* Total */}
            <div style={styles.section}>
                <label>Total Amount</label>
                <input
                    type="number"
                    value={total}
                    onChange={(e) => setTotal(parseFloat(e.target.value) || 0)}
                    style={styles.input}
                />
            </div>

            {/* Toggles */}
            <div style={styles.row}>
                <label>
                    <input
                        type="checkbox"
                        checked={isEqualSplit}
                        onChange={() => setIsEqualSplit((p) => !p)}
                    />
                    Equal Split
                </label>

                <label>
                    <input
                        type="checkbox"
                        checked={autoAdjust}
                        onChange={() => setAutoAdjust((p) => !p)}
                    />
                    Auto-adjust
                </label>
            </div>

            {/* Progress bar */}
            <div style={styles.progressBar}>
                <div
                    style={{
                        ...styles.progressFill,
                        width: `${progress}%`,
                        background: isValid ? "#4caf50" : "#ff9800"
                    }}
                />
            </div>

            {/* Participants */}
            <div style={styles.section}>
                {participants.length === 0 && (
                    <p>No participants. Add one 👇</p>
                )}

                {participants.map((p, index) => {
                    const hasError = !isEqualSplit && !isValid;

                    return (
                        <div key={p.id} style={styles.row}>
                            <input
                                type="text"
                                placeholder="Name"
                                value={p.name}
                                onChange={(e) => {
                                    const updated = [...participants];
                                    updated[index].name = e.target.value;
                                    setParticipants(updated);
                                }}
                                style={styles.input}
                            />

                            <input
                                type="number"
                                value={p.amount}
                                disabled={isEqualSplit}
                                onChange={(e) =>
                                    handleAmountChange(p.id, e.target.value)
                                }
                                style={{
                                    ...styles.input,
                                    borderColor: hasError ? "red" : "#ccc"
                                }}
                            />

                            <button onClick={() => removeParticipant(p.id)}>
                                ❌
                            </button>
                        </div>
                    );
                })}
            </div>

            {/* Actions */}
            <div style={styles.row}>
                <button onClick={addParticipant}>+ Add</button>
            </div>

            {/* Summary */}
            <div style={styles.summary}>
                <p>Total: ₹{total.toFixed(2)}</p>
                <p>Allocated: ₹{totalAllocated.toFixed(2)}</p>

                <p style={{ color: isValid ? "green" : "red" }}>
                    Remaining: ₹{remaining}
                </p>

                {!isValid && (
                    <p style={{ color: "red" }}>
                        ⚠️ Adjust amounts to match total
                    </p>
                )}

                <button disabled={!isValid} style={styles.payBtn}>
                    ✅ Confirm Split
                </button>
            </div>
        </div>
    );
}

const styles = {
    container: {
        maxWidth: 500,
        margin: "20px auto",
        fontFamily: "sans-serif",
        padding: 20,
        border: "1px solid #ddd",
        borderRadius: 10
    },
    section: {
        marginTop: 15
    },
    row: {
        display: "flex",
        gap: 10,
        alignItems: "center",
        marginTop: 10
    },
    input: {
        padding: 8,
        flex: 1,
        borderRadius: 5,
        border: "1px solid #ccc"
    },
    progressBar: {
        height: 8,
        background: "#eee",
        borderRadius: 5,
        marginTop: 10
    },
    progressFill: {
        height: "100%",
        borderRadius: 5
    },
    summary: {
        marginTop: 20
    },
    payBtn: {
        marginTop: 10,
        width: "100%",
        padding: 10,
        background: "#4caf50",
        color: "white",
        border: "none",
        borderRadius: 5,
        cursor: "pointer"
    }
};
